Node* BalanceTree(Node* node) {
  if (node == nullptr) return node;

  UpdateHeightAndBalance(node);

  // Если балансировка узла имеет значение 2, и левый потомок имеет баланс 0 или 1,
  // значит, дерево право-тяжелое и требуется левая ротация.
  if (node->balance == 2 && node->left->balance >= 0) {
      return RightRotation(node);
  }
  // Малая левая, затем большая правая ротация
  if (node->balance == 2 && node->left->balance < 0) {
      node->left = LeftRotation(node->left);
      return RightRotation(node);
  }
  // Если балансировка узла имеет значение -2, и правый потомок имеет баланс 0 или -1,
  // значит, дерево лево-тяжелое и требуется правая ротация.
  if (node->balance == -2 && node->right->balance <= 0) {
      return LeftRotation(node);
  }
  // Малая правая, затем большая левая ротация
  if (node->balance == -2 && node->right->balance > 0) {
      node->right = RightRotation(node->right);
      return LeftRotation(node);
  }

  return node;
}
```

